// Cloudflare Worker: Third-party API Integration (SendGrid + Stripe)
// wrangler.toml configuration should include:
// [vars]
// SENDGRID_API_KEY = ""
// STRIPE_SECRET_KEY = ""
// API_AUTH_TOKEN = ""

const CORS_HEADERS = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  'Access-Control-Max-Age': '86400',
};

class AppError extends Error {
  constructor(message, statusCode = 500, code = 'INTERNAL_ERROR') {
    super(message);
    this.statusCode = statusCode;
    this.code = code;
  }
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      ...CORS_HEADERS,
    },
  });
}

function errorResponse(error) {
  const statusCode = error.statusCode || 500;
  const code = error.code || 'INTERNAL_ERROR';
  const message = error.message || 'An unexpected error occurred';

  console.error(`[ERROR] ${code}: ${message}`);

  return jsonResponse(
    {
      success: false,
      error: {
        code,
        message: statusCode === 500 ? 'An unexpected error occurred' : message,
      },
    },
    statusCode
  );
}

function authenticateRequest(request, env) {
  const authHeader = request.headers.get('Authorization');

  if (!authHeader) {
    throw new AppError('Missing Authorization header', 401, 'UNAUTHORIZED');
  }

  const [scheme, token] = authHeader.split(' ');

  if (scheme !== 'Bearer' || !token) {
    throw new AppError('Invalid Authorization format. Use: Bearer <token>', 401, 'UNAUTHORIZED');
  }

  if (token !== env.API_AUTH_TOKEN) {
    throw new AppError('Invalid API token', 403, 'FORBIDDEN');
  }

  return true;
}

// ==================== SendGrid Email Service ====================

async function sendEmail(env, { to, from, subject, text, html, templateId, dynamicTemplateData }) {
  if (!env.SENDGRID_API_KEY) {
    throw new AppError('SendGrid API key not configured', 500, 'CONFIG_ERROR');
  }

  if (!to || !from || !subject) {
    throw new AppError('Missing required email fields: to, from, subject', 400, 'VALIDATION_ERROR');
  }

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const toAddresses = Array.isArray(to) ? to : [to];

  for (const addr of toAddresses) {
    const email = typeof addr === 'string' ? addr : addr.email;
    if (!emailRegex.test(email)) {
      throw new AppError(`Invalid email address: ${email}`, 400, 'VALIDATION_ERROR');
    }
  }

  const personalizations = [
    {
      to: toAddresses.map((addr) => (typeof addr === 'string' ? { email: addr } : addr)),
    },
  ];

  if (dynamicTemplateData) {
    personalizations[0].dynamic_template_data = dynamicTemplateData;
  }

  const payload = {
    personalizations,
    from: typeof from === 'string' ? { email: from } : from,
    subject,
  };

  if (templateId) {
    payload.template_id = templateId;
  } else {
    payload.content = [];
    if (text) payload.content.push({ type: 'text/plain', value: text });
    if (html) payload.content.push({ type: 'text/html', value: html });
    if (payload.content.length === 0) {
      throw new AppError('Email must have text or html content, or a templateId', 400, 'VALIDATION_ERROR');
    }
  }

  const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${env.SENDGRID_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(payload),
  });

  if (!response.ok) {
    let errorBody;
    try {
      errorBody = await response.json();
    } catch {
      errorBody = await response.text();
    }

    console.error('[SendGrid Error]', JSON.stringify(errorBody));

    if (response.status === 429) {
      throw new AppError('SendGrid rate limit exceeded. Please try again later.', 429, 'RATE_LIMITED');
    }

    if (response.status === 401) {
      throw new AppError('SendGrid authentication failed', 500, 'SENDGRID_AUTH_ERROR');
    }

    throw new AppError(
      `SendGrid API error: ${response.status}`,
      response.status >= 500 ? 502 : 400,
      'SENDGRID_ERROR'
    );
  }

  return {
    success: true,
    messageId: response.headers.get('X-Message-Id'),
    statusCode: response.status,
  };
}

// ==================== Stripe Payment Service ====================

async function stripeRequest(env, endpoint, method = 'GET', body = null) {
  if (!env.STRIPE_SECRET_KEY) {
    throw new AppError('Stripe secret key not configured', 500, 'CONFIG_ERROR');
  }

  const url = `https://api.stripe.com/v1${endpoint}`;
  const headers = {
    Authorization: `Bearer ${env.STRIPE_SECRET_KEY}`,
    'Content-Type': 'application/x-www-form-urlencoded',
  };

  const options = { method, headers };

  if (body && (method === 'POST' || method === 'PUT' || method === 'PATCH')) {
    options.body = encodeStripeParams(body);
  }

  const response = await fetch(url, options);
  const data = await response.json();

  if (!response.ok) {
    console.error('[Stripe Error]', JSON.stringify(data));

    const stripeError = data.error || {};
    const message = stripeError.message || 'Stripe API error';
    const code = stripeError.code || 'STRIPE_ERROR';

    if (response.status === 429) {
      throw new AppError('Stripe rate limit exceeded', 429, 'RATE_LIMITED');
    }

    if (stripeError.type === 'card_error') {
      throw new AppError(message, 400, `CARD_ERROR_${(code || '').toUpperCase()}`);
    }

    if (stripeError.type === 'invalid_request_error') {
      throw new AppError(message, 400, 'STRIPE_INVALID_REQUEST');
    }

    throw new AppError(message, response.status >= 500 ? 502 : 400, 'STRIPE_ERROR');
  }

  return data;
}

function encodeStripeParams(obj, prefix = '') {
  const parts = [];

  for (const [key, value] of Object.entries(obj)) {
    const fullKey = prefix ? `${prefix}[${key}]` : key;

    if (value === null || value === undefined) {
      continue;
    }

    if (typeof value === 'object' && !Array.isArray(value)) {
      parts.push(encodeStripeParams(value, fullKey));
    } else if (Array.isArray(value)) {
      value.forEach((item, index) => {
        if (typeof item === 'object') {
          parts.push(encodeStripeParams(item, `${fullKey}[${index}]`));
        } else {
          parts.push(`${encodeURIComponent(`${fullKey}[${index}]`)}=${encodeURIComponent(item)}`);
        }
      });
    } else {
      parts.push(`${encodeURIComponent(fullKey)}=${encodeURIComponent(value)}`);
    }
  }

  return parts.filter(Boolean).join('&');
}

async function createPaymentIntent(env, { amount, currency = 'usd', customerId, metadata, description, receiptEmail }) {
  if (!amount || amount < 50) {
    throw new AppError('Amount must be at least 50 cents', 400, 'VALIDATION_ERROR');
  }

  const validCurrencies = ['usd', 'eur', 'gbp', 'cad', 'aud', 'jpy'];
  if (!validCurrencies.includes(currency.toLowerCase())) {
    throw new AppError(`Invalid currency. Supported: ${validCurrencies.join(', ')}`, 400, 'VALIDATION_ERROR');
  }

  const params = {
    amount: Math.round(amount),
    currency: currency.toLowerCase(),
    automatic_payment_methods: { enabled: 'true' },
  };

  if (customerId) params.customer = customerId;
  if (description) params.description = description;
  if (receiptEmail) params.receipt_email = receiptEmail;
  if (metadata) params.metadata = metadata;

  return stripeRequest(env, '/payment_intents', 'POST', params);
}

async function createCustomer(env, { email, name, phone, metadata }) {
  if (!email) {
    throw new AppError('Customer email is required', 400, 'VALIDATION_ERROR');
  }

  const params = { email };
  if (name) params.name = name;
  if (phone) params.phone = phone;
  if (metadata) params.metadata = metadata;

  return stripeRequest(env, '/customers', 'POST', params);
}

async function getCustomer(env, customerId) {
  if (!customerId) {
    throw new AppError('Customer ID is required', 400, 'VALIDATION_ERROR');
  }

  return stripeRequest(env, `/customers/${encodeURIComponent(customerId)}`);
}

async function listPaymentIntents(env, { customerId, limit = 10, startingAfter }) {
  const params = new URLSearchParams();
  params.set('limit', Math.min(Math.max(limit, 1), 100).toString());
  if (customerId) params.set('customer', customerId);
  if (startingAfter) params.set('starting_after', startingAfter);

  return stripeRequest(env, `/payment_intents?${params.toString()}`);
}

async function createCheckoutSession(env, { lineItems, successUrl, cancelUrl, customerId, mode = 'payment', metadata }) {
  if (!lineItems || !lineItems.length) {
    throw new AppError('At least one line item is required', 400, 'VALIDATION_ERROR');
  }

  if (!successUrl || !cancelUrl) {
    throw new AppError('successUrl and cancelUrl are required', 400, 'VALIDATION_ERROR');
  }

  const params = {
    success_url: successUrl,
    cancel_url: cancelUrl,
    mode,
  };

  lineItems.forEach((item, index) => {
    if (item.priceId) {
      params[`line_items[${index}][price]`] = item.priceId;
    } else {
      params[`line_items[${index}][price_data][currency]`] = item.currency || 'usd';
      params[`line_items[${index}][price_data][product_data][name]`] = item.name;
      params[`line_items[${index}][price_data][unit_amount]`] = item.amount;
      if (mode === 'subscription') {
        params[`line_items[${index}][price_data][recurring][interval]`] = item.interval || 'month';
      }
    }
    params[`line_items[${index}][quantity]`] = item.quantity || 1;
  });

  if (customerId) params.customer = customerId;
  if (metadata) params.metadata = metadata;

  return stripeRequest(env, '/checkout/sessions', 'POST', params);
}

// ==================== Stripe Webhook Handler ====================

async function handleStripeWebhook(request, env) {
  const signature = request.headers.get('stripe-signature');

  if (!signature) {
    throw new AppError('Missing Stripe signature', 400, 'WEBHOOK_ERROR');
  }

  const body = await request.text();

  if (env.STRIPE_WEBHOOK_SECRET) {
    const isValid = await verifyStripeSignature(body, signature, env.STRIPE_WEBHOOK_SECRET);
    if (!isValid) {
      throw new AppError('Invalid Stripe webhook signature', 400, 'WEBHOOK_SIGNATURE_ERROR');
    }
  }

  const event = JSON.parse(body);

  console.log(`[Stripe Webhook] Received event: ${event.type}, id: ${event.id}`);

  switch (event.type) {
    case 'payment_intent.succeeded': {
      const paymentIntent = event.data.object;
      console.log(`[Payment Success] PaymentIntent ${paymentIntent.id} for ${paymentIntent.amount} ${paymentIntent.currency}`);

      if (paymentIntent.receipt_email) {
        try {
          await sendEmail(env, {
            to: paymentIntent.receipt_email,
            from: env.FROM_EMAIL || 'noreply@example.com',
            subject: 'Payment Confirmation',
            html: `
              <h1>Payment Received</h1>
              <p>Thank you for your payment of ${(paymentIntent.amount / 100).toFixed(2)} ${paymentIntent.currency.toUpperCase()}.</p>
              <p>Payment ID: ${paymentIntent.id}</p>
            `,
            text: `Payment Received. Amount: ${(paymentIntent.amount / 100).toFixed(2)} ${paymentIntent.currency.toUpperCase()}. Payment ID: ${paymentIntent.id}`,
          });
        } catch (emailError) {
          console.error('[Webhook] Failed to send confirmation email:', emailError.message);
        }
      }
      break;
    }

    case 'payment_intent.payment_failed': {
      const failedPayment = event.data.object;
      console.log(`[Payment Failed] PaymentIntent ${failedPayment.id}: ${failedPayment.last_payment_error?.message}`);
      break;
    }

    case 'checkout.session.completed': {
      const session = event.data.object;
      console.log(`[Checkout Complete] Session ${session.id}, customer: ${session.customer}`);
      break;
    }

    case 'customer.subscription.created':
    case 'customer.subscription.updated':
    case 'customer.subscription.deleted': {
      const subscription = event.data.object;
      console.log(`[Subscription ${event.type.split('.').pop()}] ${subscription.id}, status: ${subscription.status}`);
      break;
    }

    default:
      console.log(`[Stripe Webhook] Unhandled event type: ${event.type}`);
  }

  return { received: true, type: event.type };
}

async function verifyStripeSignature(payload, signature, secret) {
  try {
    const parts = signature.split(',').reduce((acc, part) => {
      const [key, value] = part.split('=');
      acc[key.trim()] = value;
      return acc;
    }, {});

    const timestamp = parts.t;
    const expectedSig = parts.v1;

    if (!timestamp || !expectedSig) return false;

    // Check timestamp tolerance (5 minutes)
    const currentTime = Math.floor(Date.now() / 1000);
    if (Math.abs(currentTime - parseInt(timestamp)) > 300) {
      console.error('[Webhook] Timestamp outside tolerance window');
      return false;
    }

    const signedPayload = `${timestamp}.${payload}`;
    const encoder = new TextEncoder();

    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(secret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['sign']
    );

    const signatureBuffer = await crypto.subtle.sign('HMAC', key, encoder.encode(signedPayload));
    const computedSig = Array.from(new Uint8Array(signatureBuffer))
      .map((b) => b.toString(16).padStart(2, '0'))
      .join('');

    return computedSig === expectedSig;
  } catch (err) {
    console.error('[Webhook] Signature verification error:', err.message);
    return false;
  }
}

// ==================== Route Handler ====================

class Router {
  constructor() {
    this.routes = [];
  }

  add(method, path, handler) {
    const pattern = path.replace(/:(\w+)/g, '(?<$1>[^/]+)');
    this.routes.push({
      method: method.toUpperCase(),
      pattern: new RegExp(`^${pattern}$`),
      handler,
    });
  }

  get(path, handler) { this.add('GET', path, handler); }
  post(path, handler) { this.add('POST', path, handler); }
  put(path, handler) { this.add('PUT', path, handler); }
  delete(path, handler) { this.add('DELETE', path, handler); }

  match(method, pathname) {
    for (const route of this.routes) {
      if (route.method !== method) continue;
      const match = pathname.match(route.pattern);
      if (match) {
        return { handler: route.handler, params: match.groups || {} };
      }
    }
    return null;
  }
}

// ==================== Rate Limiter (using Cloudflare KV or in-memory) ====================

class RateLimiter {
  constructor(env) {
    this.kv = env.RATE_LIMIT_KV || null;
    this.cache = new Map();
  }

  async check(key, limit = 60, windowSeconds = 60) {
    const now = Math.floor(Date.now() / 1000);
    const windowKey = `ratelimit:${key}:${Math.floor(now / windowSeconds)}`;

    let count;

    if (this.kv) {
      const current = await this.kv.get(windowKey);
      count = current ? parseInt(current) + 1 : 1;
      await this.kv.put(windowKey, count.toString(), { expirationTtl: windowSeconds * 2 });
    } else {
      count = (this.cache.get(windowKey) || 0) + 1;
      this.cache.set(windowKey, count);
      // Clean old entries
      if (this.cache.size > 10000) {
        const cutoff = `ratelimit:${key}:${Math.floor(now / windowSeconds) - 2}`;
        for (const k of this.cache.keys()) {
          if (k < cutoff) this.cache.delete(k);
        }
      }
    }

    if (count > limit) {
      throw new AppError('Rate limit exceeded', 429, 'RATE_LIMITED');
    }

    return { remaining: limit - count, limit };
  }
}

