// ---- Combined: Create customer, payment intent, and send receipt ----

router.post('/api/checkout', async (request, env) => {
  authenticateRequest(request, env);

  const { email, name, amount, currency, description, metadata } = await request.json();

  if (!email || !amount) {
    throw new AppError('email and amount are required', 400, 'VALIDATION_ERROR');
  }

  // 1. Create or retrieve customer
  const customer = await createCustomer(env, { email, name, metadata });

  // 2. Create payment intent
  const paymentIntent = await createPaymentIntent(env, {
    amount,
    currency,
    customerId: customer.id,
    description,
    receiptEmail: email,
    metadata: { ...metadata, customerName: name },
  });

  // 3. Send notification email
  try {
    await sendEmail(env, {
      to: email,
      from: env.FROM_EMAIL || 'noreply@example.com',
      subject: 'Your Payment Link',
      html: `
        <h1>Complete Your Payment</h1>
        <p>Hi ${name || 'there'},</p>
        <p>Your payment of <strong>${(amount / 100).toFixed(2)} ${(currency || 'usd').toUpperCase()}</strong> is ready to be processed.</p>
        <p>Payment Reference: ${paymentIntent.id}</p>
        ${description ? `<p>Description: ${description}</p>` : ''}
      `,
      text: `Complete your payment of ${(amount / 100).toFixed(2)} ${(currency || 'usd').toUpperCase()}. Reference: ${paymentIntent.id}`,
    });
  } catch (emailError) {
    console.error('[Checkout] Email notification failed:', emailError.message);
    // Don't fail the whole checkout if email fails
  }

  return jsonResponse({
    success: true,
    data: {
      customer: { id: customer.id, email: customer.email },
      paymentIntent: {
        id: paymentIntent.id,
        clientSecret: paymentIntent.client_secret,
        amount: paymentIntent.amount,
        currency: paymentIntent.currency,
        status: paymentIntent.status,
      },
    },
  }, 201);
});

// ==================== Worker Entry Point ====================

export default {
  async fetch(request, env, ctx) {
    // Handle CORS preflight
    if (request.method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: CORS_HEADERS });
    }

    try {
      const url = new URL(request.url);
      const pathname = url.pathname.replace(/\/+$/, '') || '/';

      // Rate limiting
      const rateLimiter = new RateLimiter(env);
      const clientIP = request.headers.get('CF-Connecting-IP') || 'unknown';

      try {
        await rateLimiter.check(clientIP, parseInt(env.RATE_LIMIT || '120'), 60);
      } catch (rateLimitError) {
        return errorResponse(rateLimitError);
      }

      // Route matching
      const match = router.match(request.method, pathname);

      if (!match) {
        return jsonResponse(
          {
            success: false,
            error: {
              code: 'NOT_FOUND',
              message: `${request.method} ${pathname} not found`,
            },
          },
          404
        );
      }

      const response = await match.handler(request, env, match.params);
      return response;
    } catch (error) {
      if (error instanceof AppError) {
        return errorResponse(error);
      }

      if (error instanceof SyntaxError) {
        return errorResponse(new AppError('Invalid JSON in request body', 400, 'INVALID_JSON'));
      }

      console.error('[Unhandled Error]', error.stack || error.message);
      return errorResponse(new AppError('Internal server error', 500, 'INTERNAL_ERROR'));
    }
  },
};